import boto3
import os
import re
import socket
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from urllib.parse import urlparse
import requests

# AWS S3 Configuration
S3_BUCKET = 'your-s3-bucket-name'
s3_client = boto3.client('s3')

# Allowlist of domains
ALLOWED_DOMAINS = ['example.com', 'anotherdomain.com']

# Check if IP is private
def is_private_ip(ip):
    private_ranges = [
        re.compile(r'^127\.'),  # Loopback
        re.compile(r'^10\.'),  # Class A private
        re.compile(r'^192\.168\.'),  # Class C private
        re.compile(r'^172\.(1[6-9]|2[0-9]|3[0-1])\.'),  # Class B private
        re.compile(r'^169\.254\.'),  # Link-local
        re.compile(r'^0\.'),  # Invalid
        re.compile(r'^255\.255\.255\.255'),  # Broadcast
    ]
    for pattern in private_ranges:
        if pattern.match(ip):
            return True
    return False

# Validate URL
def validate_url(url):
    parsed_url = urlparse(url)
    domain = parsed_url.netloc
    if domain not in ALLOWED_DOMAINS:
        return False
    try:
        ip = socket.gethostbyname(domain)
        if is_private_ip(ip):
            return False
    except socket.error:
        return False
    return True

# Capture screenshot
def capture_screenshot(url):
    if not validate_url(url):
        raise ValueError("Invalid or disallowed URL")

    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")

    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)
    screenshot = driver.get_screenshot_as_png()
    driver.quit()
    return screenshot

# Upload to S3
def upload_to_s3(screenshot, filename):
    s3_client.put_object(Bucket=S3_BUCKET, Key=filename, Body=screenshot, ContentType='image/png')

# Main function
def generate_thumbnail(url):
    try:
        screenshot = capture_screenshot(url)
        filename = f"screenshots/{urlparse(url).netloc}.png"
        upload_to_s3(screenshot, filename)
        return f"https://{S3_BUCKET}.s3.amazonaws.com/{filename}"
    except Exception as e:
        return str(e)

